//! Behavioral tests targeting confirmed bugs in section properties and
//! header/footer/story handling.
//!
//! Each test asserts *correct* spec-defined behavior.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/section-story-bugs/create_fixtures.py`.

use stemma::{BlockNode, CanonDoc, HeaderFooterKind, InlineNode, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/section-story-bugs";
const SECTION_CONSTRAINT_FIXTURES: &str = "testdata/spec-compliance/section-constraints";

// -- helpers ----------------------------------------------------------------

/// Extract plain text from tracked blocks.
fn blocks_text(blocks: &[TrackedBlock]) -> String {
    let mut text = String::new();
    for tb in blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    text.push_str(&t.text);
                }
            }
        }
    }
    text
}

/// Collect all mid-document section properties (from pPr/sectPr).
fn section_paragraphs(doc: &CanonDoc) -> Vec<&stemma::SectionProperties> {
    let mut props = Vec::new();
    collect_section_props_tracked(&doc.blocks, &mut props);
    props
}

fn collect_section_props_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_section_props_bare<'a>(
    blocks: &'a [BlockNode],
    out: &mut Vec<&'a stemma::SectionProperties>,
) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => {
                if let Some(ref sp) = p.section_properties {
                    out.push(sp);
                }
            }
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_section_props_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

// ==========================================================================
// Bug 1: SectionType::NextColumn (ECMA-376 section 17.6.22)
// ==========================================================================

/// ECMA-376 section 17.6.22: w:type w:val="nextColumn" is a valid section break type.
#[test]
fn spec_next_column_section_type_parses() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "next-column-section-type");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );

    assert_eq!(
        section_props[0].section_type,
        Some(stemma::domain::SectionType::NextColumn),
        "ECMA-376 section 17.6.22: section_type should be NextColumn, got {:?}",
        section_props[0].section_type
    );
}

// ==========================================================================
// titlePg gates DISPLAY, not CONTENT (ISO 29500-1 §17.10.6)
// ==========================================================================
//
// ISO 29500-1 §17.10.6 governs whether the title-page header/footer is SHOWN
// ("SHALL NOT be shown" when titlePg is absent), NOT whether the reference or
// story exists in the file. Word preserves first-page header/footer references
// in the sectPr even when titlePg is off; they become active again the moment
// titlePg is toggled on. The parsed model therefore carries First-kind refs and
// stories verbatim; the display rule is the consumer's to apply from
// `title_page` at render time. The model must never destroy these refs/stories.

/// titlePg absent: the First-kind header reference is still carried in the
/// model (display is gated by `title_page`, not the stored reference).
#[test]
fn spec_title_page_absent_preserves_first_header_ref() {
    let (_rt, doc) = common::import_fixture(SECTION_CONSTRAINT_FIXTURES, "title-page-absent");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should be Some");

    assert!(
        body_sp.title_page != Some(true),
        "title_page should not be Some(true) when titlePg is absent, got {:?}",
        body_sp.title_page
    );

    let first_refs: Vec<_> = body_sp
        .header_refs
        .iter()
        .filter(|r| r.kind == HeaderFooterKind::First)
        .collect();
    assert_eq!(
        first_refs.len(),
        1,
        "First-kind header ref must be preserved even when titlePg is absent \
         (display is gated by title_page, not by mutating the model), got {first_refs:?}"
    );
}

/// titlePg explicitly false: the First-kind header reference is still carried.
#[test]
fn spec_title_page_explicit_false_preserves_first_header_ref() {
    let (_rt, doc) = common::import_fixture(SECTION_CONSTRAINT_FIXTURES, "title-page-false");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should be Some");

    assert!(
        body_sp.title_page != Some(true),
        "title_page should not be Some(true) when titlePg val='false', got {:?}",
        body_sp.title_page
    );

    let first_refs: Vec<_> = body_sp
        .header_refs
        .iter()
        .filter(|r| r.kind == HeaderFooterKind::First)
        .collect();
    assert_eq!(
        first_refs.len(),
        1,
        "First-kind header ref must be preserved even when titlePg=false \
         (display is gated by title_page, not by mutating the model), got {first_refs:?}"
    );
}

/// The First-kind header STORY must be preserved in `doc.headers` even when no
/// section has titlePg=true — the part exists in the package regardless of
/// whether the title-page header is currently displayed.
#[test]
fn spec_title_page_absent_first_header_story_preserved() {
    let (_rt, doc) = common::import_fixture(SECTION_CONSTRAINT_FIXTURES, "title-page-absent");

    let first_stories: Vec<_> = doc
        .headers
        .iter()
        .filter(|h| h.kind == HeaderFooterKind::First)
        .collect();
    assert_eq!(
        first_stories.len(),
        1,
        "doc.headers must preserve the First-kind story even when no section has \
         titlePg=true (the part exists in the package regardless of display), \
         got {} First-kind stories",
        first_stories.len()
    );
}

// ==========================================================================
// Bug 3: Blank header synthesis (ECMA-376 section 17.10.2)
// ==========================================================================

/// ECMA-376 section 17.10.2: First section with no headerReference should get
/// a synthesized blank header (multi-section document).
#[test]
fn spec_first_section_no_header_gets_blank_default() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "first-section-no-header");

    let mid_sections = section_paragraphs(&doc);
    assert!(
        !mid_sections.is_empty(),
        "fixture should have at least one mid-document section break"
    );

    let first_sp = mid_sections[0];
    let default_ref = first_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default);
    assert!(
        default_ref.is_some(),
        "first section must have a Default header ref (synthesized blank)"
    );

    // The synthesized header story must exist in doc.headers
    let part_path = &default_ref.unwrap().part_path;
    let story = doc.headers.iter().find(|h| &h.part_name == part_path);
    assert!(
        story.is_some(),
        "synthesized header story must exist in doc.headers"
    );

    // The story should be empty (one paragraph with no text)
    let story = story.unwrap();
    assert_eq!(
        story.blocks.len(),
        1,
        "blank header should have one paragraph"
    );
    if let BlockNode::Paragraph(p) = &story.blocks[0].block {
        assert!(
            p.all_inlines().next().is_none(),
            "blank header paragraph should have no inlines"
        );
    } else {
        panic!("blank header story block should be a paragraph");
    }
}

/// ECMA-376 section 17.10.2: Single-section document with no headerReference
/// should have a synthesized blank default header.
#[test]
fn spec_single_section_no_header_gets_blank_default() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "single-section-no-header");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("single-section doc must have body_section_properties");

    let default_ref = body_sp
        .header_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default);
    assert!(
        default_ref.is_some(),
        "body section must have a Default header ref (synthesized blank)"
    );

    // The synthesized header story must exist in doc.headers
    let part_path = &default_ref.unwrap().part_path;
    let story = doc.headers.iter().find(|h| &h.part_name == part_path);
    assert!(
        story.is_some(),
        "synthesized header story must exist in doc.headers"
    );

    // The story should be empty (one paragraph with no text)
    let story = story.unwrap();
    assert_eq!(
        story.blocks.len(),
        1,
        "blank header should have one paragraph"
    );
    if let BlockNode::Paragraph(p) = &story.blocks[0].block {
        assert!(
            p.all_inlines().next().is_none(),
            "blank header paragraph should have no inlines"
        );
    } else {
        panic!("blank header story block should be a paragraph");
    }
}

// ==========================================================================
// Bug 4: Continuous section partial margin inheritance (ECMA-376 section 17.6.22)
// ==========================================================================

/// ECMA-376 section 17.6.22: Continuous section inherits page properties from
/// the preceding section, but explicit declarations take precedence.
#[test]
fn spec_continuous_section_partial_margin_inheritance() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "continuous-section-partial-margins");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );

    let s1 = section_props[0];
    assert_eq!(
        s1.margin_top,
        Some(1440),
        "S1 margin_top should be 1440, got {:?}",
        s1.margin_top
    );
    assert_eq!(
        s1.margin_left,
        Some(1440),
        "S1 margin_left should be 1440, got {:?}",
        s1.margin_left
    );

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");

    assert_eq!(
        body_sp.section_type,
        Some(stemma::domain::SectionType::Continuous),
        "Section 2 should be continuous, got {:?}",
        body_sp.section_type
    );

    assert_eq!(
        body_sp.margin_left,
        Some(720),
        "ECMA-376 section 17.6.22: Section 2 explicitly declares left=720, got {:?}",
        body_sp.margin_left
    );

    assert_eq!(
        body_sp.margin_top,
        Some(1440),
        "ECMA-376 section 17.6.22: Section 2 should inherit top=1440 from Section 1, got {:?}",
        body_sp.margin_top
    );
    assert_eq!(
        body_sp.margin_bottom,
        Some(1440),
        "ECMA-376 section 17.6.22: Section 2 should inherit bottom=1440 from Section 1, got {:?}",
        body_sp.margin_bottom
    );
    assert_eq!(
        body_sp.margin_right,
        Some(1440),
        "ECMA-376 section 17.6.22: Section 2 should inherit right=1440 from Section 1, got {:?}",
        body_sp.margin_right
    );
}

// ==========================================================================
// Bug 5: Footer per-kind inheritance (ECMA-376 section 17.10.2)
// ==========================================================================

/// ECMA-376 section 17.10.2: Per-kind footer inheritance across sections.
///
/// S1: default + first footers. S2: only first footer.
/// S2 should inherit S1's default footer and use its own first footer.
#[test]
fn spec_footer_per_kind_inheritance() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "footer-per-kind-inheritance");

    assert_eq!(
        doc.footers.len(),
        3,
        "should have 3 footer stories, got {}",
        doc.footers.len()
    );

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section"
    );

    let s1_sp = section_props[0];
    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist (Section 2)");

    assert_eq!(
        s1_sp.footer_refs.len(),
        2,
        "S1 should have 2 footer refs (default + first), got {:?}",
        s1_sp.footer_refs
    );

    assert_eq!(
        body_sp.footer_refs.len(),
        2,
        "S2 should have 2 footer refs (inherited default + own first), got {:?}",
        body_sp.footer_refs
    );

    let s1_default = s1_sp
        .footer_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .expect("S1 should have a Default footer ref");
    let s2_default = body_sp
        .footer_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::Default)
        .expect("S2 should have a Default footer ref (inherited from S1)");
    assert_eq!(
        s1_default.part_path, s2_default.part_path,
        "ECMA-376 section 17.10.2: S2's default footer should be inherited from S1. \
         S1 default part_path={}, S2 default part_path={}",
        s1_default.part_path, s2_default.part_path
    );

    let s1_first = s1_sp
        .footer_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First)
        .expect("S1 should have a First footer ref");
    let s2_first = body_sp
        .footer_refs
        .iter()
        .find(|r| r.kind == HeaderFooterKind::First)
        .expect("S2 should have a First footer ref");
    assert_ne!(
        s1_first.part_path, s2_first.part_path,
        "ECMA-376 section 17.10.2: S2's first footer should be its own, not inherited from S1. \
         S1 first part_path={}, S2 first part_path={}",
        s1_first.part_path, s2_first.part_path
    );

    let s2_default_story = doc
        .footers
        .iter()
        .find(|f| f.part_name == s2_default.part_path)
        .expect("should find footer story for S2's default footer");
    let text = blocks_text(&s2_default_story.blocks);
    assert!(
        text.contains("S1 Default Footer"),
        "S2's inherited default footer should contain 'S1 Default Footer', got: '{text}'"
    );

    let s2_first_story = doc
        .footers
        .iter()
        .find(|f| f.part_name == s2_first.part_path)
        .expect("should find footer story for S2's first footer");
    let text = blocks_text(&s2_first_story.blocks);
    assert!(
        text.contains("S2 First Footer"),
        "S2's first footer should contain 'S2 First Footer', got: '{text}'"
    );
}
